mapper.update:
update roles
set role_name = #{roleName},
    description = #{description},
    version = #{version} + 1,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where role_id = #{roleId}
  and version = #{version}
  and is_deleted = 'n'

update roles
set is_deleted = 'y',
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where role_id = #{roleId}
